var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"로웰 양이라고 했지.","JPN":"ローウェル君と言ったな。","ENG":"Lowell, was it?","TWN":"你叫勞威爾對吧？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"떠나기 전에 잠시 이야기를 나눌 수 있을까?","JPN":"戻る前に、少し話せるかね？","ENG":"Could I have a word with you before you go?","TWN":"離開前可以聊幾句嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……당신은?","JPN":"……あなたは？","ENG":"...You're?","TWN":"……你是？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"클리포트 게임에서 봤던 기억이 있습니다. 분명…….","JPN":"クリフォトゲームでお会いしましたよね。確か……","ENG":"I remember seeing you at the Qliphoth Game. You're the...","TWN":"我記得在逆卡巴拉遊戲中有見過你，你是……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"지금은 그냥 코치일 뿐이라네.","JPN":"今はただのコーチだ。","ENG":"Right now, I'm just a coach.","TWN":"我現在就只是一名教練。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"코치라고요……?","JPN":"コーチですか……？","ENG":"A coach...?","TWN":"教練嗎……？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"어쩌면 저희가 이번 리그를 너무 쉽게 생각했던 걸지도 모르겠군요.","JPN":"もしかすると私たちは今回のリーグを甘く見すぎていたのかもしれませんね。","ENG":"Perhaps we underestimated this year's league.","TWN":"或許我們把這次的聯賽看得太簡單了。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아니, 자네들은 무척 힘든 상대였다네.","JPN":"いや、君たちはとても手強かった。","ENG":"No, your team was a formidable opponent.","TWN":"不，你們是相當可敬的對手。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 마지막에 승부를 포기하지 않았다면, 어느 한 쪽이 크게 다치고 말았을 거야.","JPN":"君が最後に勝負を諦めてくれなかったら、どちらかが酷い怪我を負うことになっただろう。","ENG":"If you hadn't given up at the last second, either side would have suffered serious injuries.","TWN":"要是你最後一刻沒有放棄奪勝，結果很可能就是兩敗俱傷。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"아니요. 그건 명백히 제 실책입니다.","JPN":"いいえ。あれは完全に私の失策でした。","ENG":"No. That was clearly my mistake.","TWN":"不，那是我個人的失誤。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"잠깐의 승부욕 때문에 기사로서 넘어서는 안 되는 선을 넘을 뻔했으니까요.","JPN":"一時の負けたくないという気持ちに屈し、騎士として越えてはならない一線を越えるところでしたから。","ENG":"I was blinded by victory and almost crossed a line that no knight should.","TWN":"我暫時被勝負給蒙蔽雙眼，差點越過那條騎士不該越過的線。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"단련이 부족한 탓이겠죠. 반성하고 있습니다.","JPN":"鍛錬が足りないせいでしょうね。反省しております。","ENG":"It is my lack of training. I must reflect on my actions.","TWN":"都怪我的訓練還不夠成熟，我會好好反省的。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 겸손하군.","JPN":"はは、謙遜だな。","ENG":"Ha ha, how modest of you.","TWN":"哈哈，你真是謙卑。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"실은 조디악 나이츠에 대해 몇 가지 듣고 싶네만, 괜찮겠나?","JPN":"実はゾディアックナイツについていくつか聞きたいのだが、構わないかね？","ENG":"Actually, I wanted to ask you a few questions about the Zodiac Knights. Is that all right with you?","TWN":"我有些十二宮騎士團的事想問你，不知道方便嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"기사단의 내부 사정을 외부에 발설하는 건, 그다지 바람직하지 못한 행동이지만…….","JPN":"騎士団内部の事情を外部に洩らすことは、あんまり望ましくない行動ですが……","ENG":"Talking about the order's internal affairs to an outsider may not be such a good idea, but...","TWN":"基本上騎士團內部的事情是不能對外透露的……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"좋습니다. 당신이라면 신뢰할 수 있겠죠.","JPN":"いいでしょう。あなたなら信用できます。","ENG":"Very well. I believe you can be trusted.","TWN":"不過好吧！我想你是信得過的！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"레드 시프트에 대해.","JPN":"レッドシフトについて。","ENG":"Tell me about Red Shift.","TWN":"我想知道紅移的事。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"오지만디아스에 대해 알고 있나?","JPN":"オジマンディアスについて知っているか？","ENG":"Do you know Ozymandias?","TWN":"你認識奧茲曼迪亞斯嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"잘 들었네.","JPN":"話してくれてありがとう。","ENG":"That will be all.","TWN":"謝謝你告訴我這些。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"조디악 나이츠는 별의 무구라는 아티팩트를 소유한 열두 가문이 결속된 기사단입니다.","JPN":"ゾディアックナイツは星の武具というアーティファクトを所有している十二名家が結束して作った騎士団です。","ENG":"The Zodiac Knights is an order formed by the twelve families that each own an Artifact called Star Armaments.","TWN":"十二宮騎士團是由十二個家族組成的，而每個家族都擁有名為星之武具的人造神器。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"하지만 세월이 흐르면서 두 계파로 나뉘어 대립하기 시작했죠.","JPN":"しかし年月の流れとともに、二つの派閥に分かれ対立し始めました。","ENG":"But as time passed, the order split into two factions.","TWN":"後來時間一久，騎士團一分為二，二大派系開始對立。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"기사도를 숭앙하며, 기사단의 정통성을 유지하려는 블루 시프트.","JPN":"騎士道を尊び、騎士団の正統性を維持しようというブルーシフト。","ENG":"Blue Shift, where chivalry was revered and traditions of the order were maintained.","TWN":"一派為追求騎士精神，重視騎士團正統性的藍移。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"무구의 힘을 사적으로 이용하여 개인의 영달을 추구하는 레드 시프트…….","JPN":"武具の力を私的に利用し、個人の繁栄を追求するレッドシフト……","ENG":"And Red Shift, where the power of Armaments was used for personal gains such as the pursuit of distinction.","TWN":"另一派則為將武具的力量挪為私用，追求個人利益的紅移……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"주도권을 쥐고 있는 건 여전히 저희 블루 시프트 측이지만.","JPN":"主導権を握っているのは、まだ私たちブルーシフトですが。","ENG":"Even though Blue Shift still has the upper hand...","TWN":"雖然主導權幾乎在我們藍移這一方，"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"갈등은 여전히 지속되고 있죠.","JPN":"相変わらず葛藤は続いている状況です。","ENG":"Conflict persists.","TWN":"但雙方卻一直處在紛歧中。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……네. 이 도시에서 마치 왕처럼 행세하고 있더군요.","JPN":"……はい。この都市ではまるで王様のように振る舞っていましたね。","ENG":"...Yes. We found out that she was acting as if she was the queen of this city.","TWN":"……認識，她在這座城市裡呼風喚雨，像個女王一樣。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그 여자의 본명은 줄리아 레온하르트. 사자자리의 기사입니다.","JPN":"彼女の本名はジュリア・レオンハルト。獅子座の騎士です。","ENG":"Her real name is Julia Leonhardt. She is the Knight of Leo.","TWN":"她的本名是茱莉亞·里恩哈特，是獅子座騎士。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"레온하르트 가문은 대대로 블루 시프트에 속했지만…….","JPN":"レオンハルト家は代々ブルーシフトに属していましたが……","ENG":"The Leonhardt family used to be with Blue Shift, but...","TWN":"里恩哈特家族歷代以來都歸屬於藍移……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그 여자는 전임기사 단장이 종적을 감춘 뒤에, 돌연 레드시프트로 전향해버렸죠.","JPN":"彼女は前任の騎士団長が行方不明になると、突如レッドシフトに転向してしまったのです。","ENG":"After the knight captain suddenly disappeared, she abruptly turned to Red Shift.","TWN":"但她將前任騎士團長的蹤跡藏匿起來後，就突然轉向紅移。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"기사단장직에 버금가는 실력을 지녔으니 회유해야 한다는 이들도 있습니다만…….","JPN":"騎士団長に匹敵する実力を持っているだけに、懐柔すべきであるという者たちもいましたが……","ENG":"Some believe she must be reconciled to our side because her skills are comparable to those of a knight captain...","TWN":"不過有些人認為她的能力很好，僅次於騎士團長，所以應該把她找回來……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"저는 그 여자의 변절을 결코 용납할 수 없습니다.","JPN":"私はあの女の裏切りを決して許せません。","ENG":"But I cannot forgive her betrayal.","TWN":"但我個人絕對無法原諒她的叛變。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"클리포트 게임 이후, 조디악 나이츠는 궁지에 몰려 있는 상황입니다.","JPN":"クリフォードゲーム以降、ゾディアックナイツは窮地に立たされています。","ENG":"The Zodiac Knights are in a difficult situation following the Qliphoth Game.","TWN":"逆卡巴拉遊戲之後，十二宮騎士團的情況很窘迫。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L50_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"구원기사단의 출현, 잇따른 관리국의 감사……. 그리고 단장님마저 종적을 감추셨죠.","JPN":"救世騎士団の出現、立て続けに行われた管理局からの監査……しまいには団長すら行方不明になってしまいました。","ENG":"The advent of the Knights of Redemption, followed by the Administration's audits... and the disappearance of our captain.","TWN":"救贖騎士團的出現，管理局的監視……連團長都下落不明。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그렇기에 저희는 기사단의 내부 분열을 더는 방관해서는 안 된다고 생각했습니다.","JPN":"であるからこそ、騎士団の内部分裂をこれ以上傍観してはいけないと判断したのです。","ENG":"That is why I decided that this internal conflict cannot be brushed under the rug any longer.","TWN":"因此我認為不能再坐視騎士團內部繼續分裂。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래서 오지만디아스에게 도전하려고 했던 건가.","JPN":"それでオジマンディアスに挑もうとしていたのか。","ENG":"Is that why you tried to challenge Ozymandias?","TWN":"所以你們才想挑戰奧茲曼迪亞斯嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그 여자가 가장 명예롭게 여기는 건틀렛 리그에서 그녀를 꺾는다면.","JPN":"あの女が最も名誉あるものと考えているガントレットリーグで彼女に勝てば。","ENG":"If we were able to beat her in what she considers her highest honor, the Gauntlet...","TWN":"我是想，若能在她視為最高榮譽的聖鎧聯賽打敗她，"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"저희의 요구도 무시하기 어려울 테니까요.","JPN":"私たちからの要求も無視できなくなるでしょうからね。","ENG":"Then it would be difficult for her to ignore our request as well.","TWN":"對於達到我們的訴求應該會很有幫助。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"물론, 단장님이 계셨다면… 기사단을 규합할 다른 방법이 있었을지도 모르겠지만요.","JPN":"もちろん団長がいらっしゃれば……騎士団を糾合する別の方法があったかもしれませんが。","ENG":"Of course, if Captain was here... then perhaps there would have been another way to unite the order.","TWN":"當然，若是團長在的話…說不定有其他方法可以使 騎士團團結起來。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"역시 자네는 펠리세트와 닮았군.","JPN":"やはり君はフェリセットに似ているな。","ENG":"You and Félicette are truly alike.","TWN":"你和費莉塞特果然很像。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……네?","JPN":"……はい？","ENG":"…Pardon?","TWN":"……什麼？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네는 자네 스스로가 최선이라고 생각하는 길을 따르면 된다고 생각하네.","JPN":"君は君自身が最善だと思う道に従えばいいのだ。","ENG":"All you need to do is follow the path that you think is best.","TWN":"我認為，你只需要選擇你認為最好的道路。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그럼, 언젠가 다른 이들도 자네의 뒤를 따르게 될 테니까.","JPN":"そうすれば、いつか他の者も君についてくるさ。","ENG":"Then one day, the others will start following you.","TWN":"那麼總有一天，其他人也會跟隨你的腳步的。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"가문 사람들에게 자신이 어떻게 비쳐질지 두려운가?","JPN":"一族の者の目に自分がどう映るかを恐れているのか？","ENG":"Are you afraid of how your family members perceive you?","TWN":"你害怕家族的人會如何看待你嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"자네보다 언니가 더 잘할 수 있을 것 같다고?","JPN":"自分より姉の方が適任だと？","ENG":"Do you think your sister is better than you?","TWN":"你覺得你姊姊會做得比你更好？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"틀렸어, 부단장.","JPN":"それは違うさ、副団長。","ENG":"You're wrong, Deputy.","TWN":"你錯了，副團長。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그들은 그저 바라볼 수밖에 없어.","JPN":"彼らはただ見守るしかないんだ。","ENG":"Your family members are just bystanders,","TWN":"他們只能看著，"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"……자네라는 별이 지나가는 궤적을.","JPN":"……君という星が描く軌跡をね。","ENG":"who are watching the arc of the star, which is you, as it passes by.","TWN":"……你這顆星星劃過的軌跡。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그러니 주위의 시선이 아닌, 언제나 부단장이 옳다고 믿는 길을 따르도록.","JPN":"だから周りを気にするのではなく、常に副団長、君自身が信じる道に従いたまえ。","ENG":"You should follow what you believe is right, instead of what others think.","TWN":"所以，副團長，不要在意周圍人的眼光，只要走在你認爲是正確的道路上。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……그렇군요. 잘 알겠습니다.","JPN":"……なるほど。よくわかりました。","ENG":"...I see. Understood.","TWN":"原來如此，我明白了。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"부단장, 무슨 이야기를 그렇게 오래 해?","JPN":"副団長、そんなに長々と何を話してたの？","ENG":"Deputy, what's taking so long?","TWN":"副團長，你們怎麼聊這麼久？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"배고프니까 빨리 숙소로 가자~","JPN":"お腹空いたし、早く宿に戻ろう～","ENG":"I'm starving, so let's head back to eat something!","TWN":"我們快回去宿舍吧，我肚子好餓～"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"조디악 나이츠의 도움이 필요하다면 언제든 말씀하세요.","JPN":"ゾディアックナイツにお力添えできることがあれば、いつでもおっしゃってください。","ENG":"If you ever need the Zodiac Knights' help, please don't hesitate to ask.","TWN":"之後若有需要十二宮騎士團的協助，不用客氣，盡管開口。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L33_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"힘이 닿는 한, 최선을 다해 돕도록 하겠습니다.","JPN":"許す限り、全力でお力添えいたします。","ENG":"We will assist you with the best of our abilities.","TWN":"我們會在能力所及的範圍內，盡可能提供協助。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네에엣!? 그 여자가 S급 카운터라구요?","JPN":"えええっ！？　今の人、Sランクカウンターだったんですか？","ENG":"Whaat?! That woman's a Grade S Counter?!","TWN":"什麼～～！？她是S級制裁者？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"<color=#ffd34c>전승 무패, 관리국 공인 S급 카운터</color>…….","JPN":"<color=#ffd34c>全勝無敗。管理局公認のSランクカウンター</color>……","ENG":"<color=#ffd34c>The undefeated, Administration confirmed Grade S Counter</color>...","TWN":"<color=#ffd34c>百戰百勝，管理局公認的S級制裁者。</color>……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그게 오지만디아스의 캐치프레이즈니까요.","JPN":"それがオジマンディアスのキャッチフレーズです。","ENG":"That is Ozymandias' catchphrase.","TWN":"這是奧茲曼迪亞斯的代名詞。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"우으으. 어제 미나 선배 뒤에서 몰래 메롱했는데, 설마 들키지는 않았겠죠?","JPN":"ううう。昨日ミナ先輩の後ろからアッカンベーしたの、バレていないでしょうね？","ENG":"Ooh. But I secretly blew a raspberry at her behind Mina. She couldn't have seen that, right?","TWN":"天啊，我昨天還在米娜前輩背後對她做鬼臉欸，她應該沒發現吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 너무 걱정 말게. 미나 양만 신경쓰는 눈치였으니까.","JPN":"はは、あまり心配しなくていい。ミナ君のことしか見ていなかったから。","ENG":"Ha ha, don't worry too much. She was too busy to notice anything besides Mina.","TWN":"哈哈，我想應該沒發現，因為她眼裡只有米娜。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으윽, 펜릴 소대의 일원으로서 그건 그것대로 자존심 상하는데요….","JPN":"うう、フェンリル小隊の一員として、それはそれでプライドが傷つきます……","ENG":"Ngh, but that too kinda hurts my pride as a member of Fenrir Squad...","TWN":"呃，身為芬里爾小隊的一員，聽到這種話很傷自尊心欸…"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"챔피언인지 뭔지 몰라도 너무 쫄지 말라고.","JPN":"チャンピオンだか何だか知らねえけど、必要以上にビビんなよ。","ENG":"Champion or not, I don't see any reason to be scared of her.","TWN":"管她是冠軍還是什麼，沒什麼好怕的吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"카운터 등급이 높다고 실전에서도 잘 싸운다는 법은 없으니까.","JPN":"カウンターランクが高いからって、実戦でも強いっていうわけじゃないんだし。","ENG":"Just because her Counter grade is high doesn't mean that she's a good fighter in practice.","TWN":"誰說制裁者的等級高就一定很能打。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"오오! 그렇네요! 미나 선배는 그 무시무시한 사슬검도 한 손으로 튕겨냈으니까!","JPN":"おお！　そうですね！　ミナ先輩はあの恐ろしい蛇腹剣も片手で弾き飛ばしたんですもんね！","ENG":"Ooh! That's true! Mina even deflected that whip sword with one hand!","TWN":"喔喔！說得也是！米娜前輩一隻手就將那把可怕的劍撥開咧！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L49_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"진짜로 싸우면 한주먹 거리도 안 될 거예요! 그렇죠, 미나 선배?","JPN":"本気で戦ったら軽く勝てますよね！　ね、ミナ先輩？","ENG":"I bet she'll go down in one punch! Isn't that right, Mina?","TWN":"要是真的打起來，一下就可以KO她吧！我說的沒錯吧，米娜前輩？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그건 아니야. 받아냈을 때 꽤 묵직했으니까.","JPN":"それはない。受け止めた時、かなり重かったから。","ENG":"Hardly. Her attack felt quite heavy when I deflected it.","TWN":"不對，我也是擋得蠻吃力的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"진심으로 공격했으면 지금처럼 한 손만으로는 받아치기 힘들었을 거야.","JPN":"もし本気の攻撃だったら、今みたいに片手で受け止めることはできなかったはずだよ。","ENG":"If she attacked with all her might, then it would've been hard for me to block it with one hand.","TWN":"要是她是來真的，我可能就無法像剛剛那樣用一隻手擋下。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그, 그럴 수가! 그 실없어 보이는 언니가 정말 그렇게 강하다고요?","JPN":"そ、そんなぁ！　あの中身がなさそうな感じのお姉さんがそんなに強いんですか？","ENG":"N-no way! She looks so shallow! You think she's really that strong?","TWN":"怎，怎麼可能！那個看起來像花瓶的姊姊有這麼厲害喔？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"응. 내가 아는 사람들 중에선…… 대령 아저씨랑 비슷해.","JPN":"うん。私の知っている中だと……大佐のおじさんぐらい強いかな。","ENG":"Yup. If I had to compare her to someone I know... she's on par with that colonel.","TWN":"嗯，以我認識的人來舉例的話……她的實力和上校大叔差不多。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"만만한 상대는 아니야. 챔피언을 노린다면 철저하게 준비하는 게 좋겠어, 펠리세트.","JPN":"油断できない相手だよ。チャンピオンを狙うなら徹底的に準備しておいた方がいいと思う、フェリセット。","ENG":"She won't be an easy opponent. If you plan on becoming champion, Félicette, then you should prepare thoroughly.","TWN":"她可不好對付，要是想奪冠就必須做好萬全的準備，費莉塞特。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"저…… 사장님?","JPN":"あの……社長？","ENG":"Uh... Boss?","TWN":"那個……老闆？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"왜 그러지, 스키너 양? 안색이 안 좋은데?","JPN":"どうしたんだ、スキナー君？　顔色が悪いぞ？","ENG":"What is it, Skinner? You don't look so good.","TWN":"史金納，你怎麼了？臉色怎麼這麼難看？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"경기가 끝나자마자 갑자기 이런 말씀드리는 게 무척 죄송스럽지만…….","JPN":"試合終了直後にこんなことを申し上げるのは大変申し訳ありませんが……","ENG":"I'm really sorry to say this right after the match, but...","TWN":"很抱歉，比賽才剛結束就提出這種要求……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"내일 휴가를 써도 괜찮을까요? 다녀와야 할 곳이 있어서요.","JPN":"明日は休ませていただいてもよろしいでしょうか？　とある場所に用事がありまして。","ENG":"Could I take a day off tomorrow? There's somewhere I need to go.","TWN":"我明天可以休假嗎？我要去個地方。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"물론이지. 우리 회사는 직원들이 휴가를 쓰는 걸로 뭐라 안 한다네.","JPN":"もちろんだ。うちの会社では社員が休暇を取ることに対して口出しはしないからね。","ENG":"Of course you can. Our company allows all employees to use their day off whenever they want.","TWN":"沒問題，我們公司是沒在擋假的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……부사장 입장은 잘 모르겠네만.","JPN":"……副社長は何と言うかわからんが。","ENG":"...Although I'm not sure what our Vice President has to say about that.","TWN":"……這純屬個人意見，副總的部分我不確定。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그…… 그리고 사장님도 같이 가주셨으면 좋겠는데요.","JPN":"あ、あとですね、社長にもご一緒していただければなと思っているのですが。","ENG":"Um... and it would be nice if you could come with me.","TWN":"老闆……我希望你能跟我一起去。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"음? 나 말인가?","JPN":"ん？　私が？","ENG":"Hmm? Me?","TWN":"什麼？我嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"네, 사장님께 소개시켜 드릴 사람이 있거든요.","JPN":"はい、社長にご紹介したい人物がいまして。","ENG":"Yes. There's someone I would like to introduce you to.","TWN":"對，我想介紹一個人給老闆認識。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"킁킁……! 미나 선배! 아무래도 냄새가 나는 것 같아요……!","JPN":"クンクン……！　ミナ先輩！　なんだか匂います……！","ENG":"*Sniff, sniff* Mina! I smell something going on...!","TWN":"嗅嗅……！米娜前輩！有可疑的味道喔……！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"무슨 냄새?","JPN":"何が？","ENG":"Smell? What smell?","TWN":"什麼可疑味道？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"위험한…… ","JPN":"これは危険な…… ","ENG":"It smells dangerous...","TWN":"孤男寡女的…… "},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"불륜의 냄새가!","JPN":"不倫の匂いです！","ENG":"It's the smell of an affair!","TWN":"那種味道！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L28_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……그런 거 하나도 안 나거든.","JPN":"……どこにもそんな匂いしないけど。","ENG":"...There's no such thing.","TWN":"……才沒有什麼味道。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};